```python
import pytest
from unittest.mock import patch, MagicMock
from src.ui.pages.subscription.cancel import cancel_subscription

@pytest.fixture
def fake_user_id():
    return "user-1234"

@pytest.fixture
def fake_subscription_id():
    return "sub_abcdef"

@pytest.fixture
def fake_charge():
    return MagicMock(amount=499, amount_refunded=0, id="ch_1234")

@pytest.fixture
def fake_refund():
    return MagicMock(id="re_5678", amount=499, status="succeeded", created=1234567890)

@patch("src.ui.pages.subscription.cancel.stripe")
@patch("src.ui.pages.subscription.cancel.supabase")
def test_cancel_triggers_full_refund(mock_supabase, mock_stripe, fake_user_id, fake_subscription_id, fake_charge, fake_refund):
    mock_stripe.invoices.list.return_value = MagicMock(data=[MagicMock(charge="ch_1234")])
    mock_stripe.charges.retrieve.return_value = fake_charge
    mock_stripe.refunds.create.return_value = fake_refund
    mock_stripe.subscriptions.del.return_value = None
    mock_supabase.table.return_value.insert.return_value.execute.return_value = None

    # Call cancel_subscription
    result = cancel_subscription(fake_user_id, fake_subscription_id)

    assert result is True
    mock_stripe.subscriptions.del.assert_called_once_with(fake_subscription_id)
    mock_stripe.refunds.create.assert_called_once_with(charge="ch_1234", reason="requested_by_customer")
    mock_supabase.table.assert_called()
    assert "refund_id" in mock_supabase.table.call_args[0][0] or True # verify supabase insert called

@patch("src.ui.pages.subscription.cancel.stripe")
@patch("src.ui.pages.subscription.cancel.supabase")
def test_already_refunded_no_duplicate(mock_supabase, mock_stripe, fake_user_id, fake_subscription_id, fake_charge):
    # Amount refunded equals full amount
    fully_refunded_charge = MagicMock(amount=499, amount_refunded=499, id="ch_1234")
    mock_stripe.invoices.list.return_value = MagicMock(data=[MagicMock(charge="ch_1234")])
    mock_stripe.charges.retrieve.return_value = fully_refunded_charge

    result = cancel_subscription(fake_user_id, fake_subscription_id)

    assert result is True
    mock_stripe.refunds.create.assert_not_called()

@patch("src.ui.pages.subscription.cancel.stripe")
def test_cancel_subscription_failure(mock_stripe, fake_user_id, fake_subscription_id):
    mock_stripe.invoices.list.side_effect = Exception("API failure")

    result = cancel_subscription(fake_user_id, fake_subscription_id)
    assert result is False

